  it("should resolve the closed promise when queue is closed after a pending get", async () => {
    const queue = Queue();

    // Start a pending get operation
    queue.get().catch(() => {});

    // Close the queue
    queue.close();

    // The closed promise should resolve in original code but not in mutated code
    const timeout = new Promise<string>((_, reject) => 
      setTimeout(() => reject(new Error("timeout")), 1000)
    );

    const closedValue = await Promise.race([
      queue.closed.then((val: unknown) => val),
      timeout
    ]);

    expect(closedValue).toBeInstanceOf(Error);
  });
});
